-- ============================================================
-- 精灵系统测试形象：0-9级 SVG 占位图（图层叠加方案）
-- ============================================================
-- 设计原则：
--   0级 = 能量球形态（3系通用形状，仅颜色和元素不同）
--   1级 = 基础身体（Lv.0 能量球碎裂 -> 基础形态出现）
--   2级 = Lv.1 + 小配件
--   3级 = Lv.2 + 特征强化
--   4级 = Lv.3 + 表情/肢体强化
--   5级 = Lv.4 + 发光层
--   6级 = Lv.5 + 粒子层
--   7级 = Lv.6 + 宝石/标记层
--   8级 = Lv.7 + 翅膀/装饰层
--   9级 = Lv.8 + 光环层（满级特殊）
-- ============================================================

-- ============================================================
-- 植物系·向日葵（0-9级，共11张）
-- ============================================================

-- Lv.0 能量球（绿色光球 + 小叶子元素）
INSERT INTO sprite_images (species, variant, level, image_url, prompt_used, is_active) VALUES
('plant','sunflower',0,'data:image/svg+xml;base64,','能量球：绿色光球+叶子','true')
ON CONFLICT (species, variant, level) DO UPDATE SET image_url=EXCLUDED.image_url;

